import React, { useState } from 'react';
import { 
  User, 
  Calendar,
  FileText,
  Users
} from 'lucide-react';
import { Card } from '../ui/card';
import { Button } from '../ui/button';
import { Input } from '../ui/input';
import { Label } from '../ui/label';
import { RadioGroup, RadioGroupItem } from '../ui/radio-group';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../ui/select';

export const ClientForm = () => {
  const [formData, setFormData] = useState({
    clientA: '',
    clientName: '',
    hearingDate: '',
    riders: [],
    caseType: 'ECAS'
  });

  const [riderCount, setRiderCount] = useState(1);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleRiderChange = (index, field, value) => {
    const updatedRiders = [...formData.riders];
    if (!updatedRiders[index]) {
      updatedRiders[index] = {};
    }
    updatedRiders[index][field] = value;
    setFormData(prev => ({
      ...prev,
      riders: updatedRiders
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
  };

  const addRider = () => {
    setRiderCount(prev => prev + 1);
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <Card className="p-6 space-y-6">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-6">Client Information Form</h2>
        
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Client A# */}
              <div className="space-y-2">
                <Label htmlFor="clientA">Client A#</Label>
                <div className="relative">
                  <FileText className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <Input
                    id="clientA"
                    name="clientA"
                    value={formData.clientA}
                    onChange={handleInputChange}
                    className="pl-10"
                    placeholder="Enter Client A#"
                  />
                </div>
              </div>

              {/* Client Name */}
              <div className="space-y-2">
                <Label htmlFor="clientName">Client Name</Label>
                <div className="relative">
                  <User className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <Input
                    id="clientName"
                    name="clientName"
                    value={formData.clientName}
                    onChange={handleInputChange}
                    className="pl-10"
                    placeholder="Enter Client Name"
                  />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Hearing Date */}
              <div className="space-y-2">
                <Label htmlFor="hearingDate">Hearing Date</Label>
                <div className="relative">
                  <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <Input
                    id="hearingDate"
                    name="hearingDate"
                    type="date"
                    value={formData.hearingDate}
                    onChange={handleInputChange}
                    className="pl-10"
                  />
                </div>
              </div>

              {/* Case Type */}
              <div className="space-y-2">
                <Label htmlFor="caseType">Case Type</Label>
                <Select
                  value={formData.caseType}
                  onValueChange={(value) => handleInputChange({ target: { name: 'caseType', value } })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select case type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="ECAS">ECAS</SelectItem>
                    <SelectItem value="Paper Case">Paper Case</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>

          {/* Riders Section */}
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <Label>Riders</Label>
              <Button type="button" onClick={addRider} variant="outline">
                Add Rider
              </Button>
            </div>

            {[...Array(riderCount)].map((_, index) => (
              <Card key={index} className="p-4 space-y-4">
                <div className="relative">
                  <Users className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <Input
                    value={formData.riders[index]?.name || ''}
                    onChange={(e) => handleRiderChange(index, 'name', e.target.value)}
                    className="pl-10"
                    placeholder="Rider Name"
                  />
                </div>

                <RadioGroup
                  value={formData.riders[index]?.ageStatus}
                  onValueChange={(value) => handleRiderChange(index, 'ageStatus', value)}
                  className="flex space-x-4"
                >
                  <div className="flex items-center space-x-2">
                    <RadioGroupItem value="minor" id={`minor-${index}`} />
                    <Label htmlFor={`minor-${index}`}>Minor</Label>
                  </div>
                  <div className="flex items-center space-x-2">
                    <RadioGroupItem value="adult" id={`adult-${index}`} />
                    <Label htmlFor={`adult-${index}`}>Adult</Label>
                  </div>
                </RadioGroup>

                <div className="relative">
                  <FileText className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <Input
                    value={formData.riders[index]?.aNumber || ''}
                    onChange={(e) => handleRiderChange(index, 'aNumber', e.target.value)}
                    className="pl-10"
                    placeholder="A#"
                  />
                </div>
              </Card>
            ))}
          </div>

          <Button type="submit" className="w-full">
            Submit Form
          </Button>
        </form>
      </Card>
    </div>
  );
};
